# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request
from flask_login import current_user, login_required
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///site.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(20), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    role = db.Column(db.String(10), default='user')
    account_status = db.Column(db.String(10), default='active')
    subscription_tier = db.Column(db.String(10), default='free')

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@login_required
def update_user(user_id):
    if current_user.role != 'admin':
        return {"message": "Unauthorized"}, 403

    user = User.query.get(user_id)
    if user is None:
        return {"message": "User not found"}, 404

    data = request.get_json()
    if 'username' in data:
        user.username = data['username']
    if 'email' in data:
        user.email = data['email']
    if 'role' in data:
        user.role = data['role']
    if 'account_status' in data:
        user.account_status = data['account_status']
    if 'subscription_tier' in data:
        user.subscription_tier = data['subscription_tier']

    db.session.commit()
    return {"message": "User updated successfully", 
            "user": {"id": user.id, 
                     "username": user.username, 
                     "email": user.email, 
                     "role": user.role, 
                     "account_status": user.account_status, 
                     "subscription_tier": user.subscription_tier}}, 200
                     
if __name__ == '__main__':
    app.run(debug=True)